// HasHighlightClip applies the HasEdge predicate on the "highlight_clip" edge.
func HasHighlightClip() predicate.HighlightPublishTask {
	return predicate.HighlightPublishTask(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, HighlightClipTable, HighlightClipColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasHighlightClipWith applies the HasEdge predicate on the "highlight_clip" edge with a given conditions (other predicates).
func HasHighlightClipWith(preds ...predicate.HighlightClip) predicate.HighlightPublishTask {
	return predicate.HighlightPublishTask(func(s *sql.Selector) {
		step := newHighlightClipStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.HighlightPublishTask) predicate.HighlightPublishTask {
	return predicate.HighlightPublishTask(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.HighlightPublishTask) predicate.HighlightPublishTask {
	return predicate.HighlightPublishTask(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.HighlightPublishTask) predicate.HighlightPublishTask {
	return predicate.HighlightPublishTask(sql.NotPredicates(p))
}
